import React, { useEffect, useState } from 'react';
import { obtenerSitios } from './services/culturaService'; // Ajusta la ruta según tu archivo

function App() {
  const [sitios, setSitios] = useState([]); // Importante: iniciar como []

  useEffect(() => {
    const cargarDatos = async () => {
      const datos = await obtenerSitios();
      setSitios(datos || []); // Asegura que siempre sea un array
    };
    cargarDatos();
  }, []);

  return (
    <div className="App">
        {/* Aquí llamas a tus componentes de páginas */}
    </div>
  );
}
